-- dim_calendar_event
ON CONFLICT DO NOTHING;

-- dim_customer (denormalised from oltp.customers, subset)
SELECT
    customer_id,
    country,
    city,
    CASE
        WHEN acquisition_source IN ('instagram','tiktok') THEN 'social'
        WHEN acquisition_source = 'affiliate'             THEN 'affiliate'
        ELSE 'direct'
    END AS segment,
    acquisition_source
FROM oltp.customers
ON CONFLICT DO NOTHING;

-- dim_product (denormalised from oltp.products + categories)
SELECT
    p.product_id,
    p.sku,
    p.product_name,
    c.category_name,
    p.seasonality_tag
FROM oltp.products p
JOIN oltp.categories c ON c.category_id = p.category_id
ON CONFLICT DO NOTHING;

-- fact_sales (50 rows aligned with orders)
SELECT
    o.order_id,
    oi.order_item_id,
    dc.customer_key,
    dp.product_key,
    dd.date_key,
    dch.channel_key,
    -- link to calendar event if order falls within event window
    (
        SELECT dce.calendar_event_key
        FROM gold.dim_calendar_event dce
        JOIN oltp.calendar_events ce ON ce.calendar_event_id = dce.calendar_event_id
        WHERE o.order_date::DATE BETWEEN ce.start_date AND ce.end_date
        ORDER BY dce.calendar_event_key
        LIMIT 1
    ) AS calendar_event_key,
    oi.quantity,
    oi.line_total         AS revenue,
    o.discount_amount     AS discount,
    o.shipping_cost,
    ROUND(oi.line_total - (p.cost_eur * oi.quantity), 2) AS margin
FROM oltp.order_items oi
JOIN oltp.orders  o  ON o.order_id   = oi.order_id
JOIN oltp.products p ON p.product_id = oi.product_id
JOIN gold.dim_customer dc  ON dc.customer_id  = o.customer_id
JOIN gold.dim_product  dp  ON dp.product_id   = oi.product_id
JOIN gold.dim_date     dd  ON dd.date          = o.order_date::DATE
JOIN gold.dim_channel  dch ON dch.channel_name = COALESCE(o.acquisition_channel, 'website')
ON CONFLICT DO NOTHING;
